shaderText:
struct Point {
   x: u32,
   y: u32,
   z: u32,
   w: u32,
}

@group(0)
@binding(0)
var<uniform> u1: Point;

@group(0)
@binding(1)
var<uniform> u2: Point;

@group(3)
@binding(2)
var<uniform> u3: Point;

@group(3)
@binding(3)
var<uniform> u4: Point;

@vertex
fn vertexMain(@location(0) pos: vec2f) -> @builtin(position) vec4f {
  return vec4f(pos, 0, 1);
}

@fragment
fn fragmentMain() -> @location(0) vec4f {
    var sum: u32 = u1.x + u1.y + u1.z + u1.w +
                   u2.x + u2.y + u2.z + u2.w + 
                   u3.x + u3.y + u3.z + u3.w + 
                   u4.x + u4.y + u4.z + u4.w;
    var expected: u32 = 136;
    if (sum == expected) {
       return vec4(1.0f, 0.0f, 0.0f, 1.0f);
    }
    return vec4(0.0f, 1.0f, 0.0f, 1.0f);
}
